frappe.ui.form.on('Sales Invoice DN', {
    allocated_amount: function (frm) {
        let total = 0;

        (frm.doc.custom_details || []).forEach(row => {
            total += flt(row.allocated_amount);
        });

        frm.set_value('custom_total_allocated_amount', total);
        frm.set_value(
            'custom_unallocated_amount',
            frm.doc.total - total
        );
    },

    custom_details_remove: function (frm) {
        let total = 0;

        (frm.doc.custom_details || []).forEach(row => {
            total += flt(row.allocated_amount);
        });

        frm.set_value('custom_total_allocated_amount', total);
        frm.set_value(
            'custom_unallocated_amount',
            frm.doc.total - total
        );
    }
});

frappe.ui.form.on('Sales Invoice', {
    onload: function (frm) {
        frm.set_query('delivery_note', 'custom_details', function () {

            // 1️⃣ 收集当前 SI 中所有 SO
            let sales_orders = [];
            (frm.doc.items || []).forEach(item => {
                if (item.sales_order && !sales_orders.includes(item.sales_order)) {
                    sales_orders.push(item.sales_order);
                }
            });

            // 2️⃣ 如果没有 SO，直接不让选
            if (!sales_orders.length) {
                return {
                    filters: {
                        name: ['=', '']
                    }
                };
            }

            // 3️⃣ 返回 DN 的筛选条件
            return {
                filters: [
                    ['Delivery Note Item', 'against_sales_order', 'in', sales_orders],
                    ['Delivery Note', 'docstatus', '=', 0]
                ]
            };
        });
    }
});
